SELECT c.CUSTOMER_NAME AS returnthis From APPS.XXCUS_CUSTOMERS C INNER JOIN INV.MTL_CUSTOMER_ITEMS ci ON c.CUSTOMER_ID = ci.CUSTOMER_ID INNER JOIN INV.MTL_CUSTOMER_ITEM_XREFS ic ON ic.CUSTOMER_ITEM_ID = ci.CUSTOMER_ITEM_ID INNER JOIN INV.MTL_SYSTEM_ITEMS_B si ON si.INVENTORY_ITEM_ID = ic.INVENTORY_ITEM_ID WHERE si.SEGMENT1 = '30075' AND ci.INACTIVE_FLAG = 'N' Group By c.CUSTOMER_NAME;
